"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[84843],{44845:(t,e,n)=>{n.r(e),n.d(e,{data:()=>a});const a={key:"v-556ad5b4",path:"/%E8%BD%AF%E4%BB%B6/Envi.html",title:"Envi",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"Envi安装教程",slug:"envi安装教程",children:[{level:3,title:"软件下载",slug:"软件下载",children:[]},{level:3,title:"安装前须知",slug:"安装前须知",children:[]},{level:3,title:"安装步骤",slug:"安装步骤",children:[]},{level:3,title:"破解步骤",slug:"破解步骤",children:[]}]},{level:2,title:"Envi多光谱大气校正",slug:"envi多光谱大气校正",children:[{level:3,title:"1.软件准备",slug:"_1-软件准备",children:[]},{level:3,title:"2.数据准备",slug:"_2-数据准备",children:[]},{level:3,title:"3.信息备份",slug:"_3-信息备份",children:[]},{level:3,title:"数据处理",slug:"数据处理",children:[]}]},{level:2,title:"Envi辐射定标",slug:"envi辐射定标",children:[{level:3,title:"1.加载数据",slug:"_1-加载数据",children:[]},{level:3,title:"（2）打开 Radiometric Calibration 工具",slug:"_2-打开-radiometric-calibration-工具",children:[]}]}],git:{updatedTime:1653622739e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"软件/Envi.md"}},18699:(t,e,n)=>{n.r(e),n.d(e,{default:()=>i});const a=(0,n(57293).uE)('<h1 id="envi" tabindex="-1"><a class="header-anchor" href="#envi" aria-hidden="true">#</a> Envi</h1><p>ENVI专题精讲:https://www.zhihu.com/column/c_1333158294290952192</p><h2 id="envi安装教程" tabindex="-1"><a class="header-anchor" href="#envi安装教程" aria-hidden="true">#</a> Envi安装教程</h2><h3 id="软件下载" tabindex="-1"><a class="header-anchor" href="#软件下载" aria-hidden="true">#</a> 软件下载</h3><h3 id="安装前须知" tabindex="-1"><a class="header-anchor" href="#安装前须知" aria-hidden="true">#</a> 安装前须知</h3><p>1.安装全程须断开电脑网络，否则易安装不成功；</p><p>2.解压和安装前先关闭360、电脑管家等所有杀毒软件，防止误杀补丁，导致安装失败；</p><p>3.ENVI适用于Win7/8.1/10(64位)系统，亲测可用！</p><h3 id="安装步骤" tabindex="-1"><a class="header-anchor" href="#安装步骤" aria-hidden="true">#</a> 安装步骤</h3><p>（1）右键以管理员身份运行</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271011446.png" alt="1629958037902"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271011339.png" alt="1629958129724"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271011340.png" alt="1629958139810"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271011318.png" alt="1629958221369"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271011362.png" alt="1629958235442"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271011152.png" alt="1629958246651"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271011572.png" alt="1629958307338"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271011755.png" alt="1629958315690"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271011932.png" alt="1629958324370"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271011142.png" alt="1629958373650"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271011591.png" alt="1629958467978"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271011100.png" alt="1629958495068"></p><h3 id="破解步骤" tabindex="-1"><a class="header-anchor" href="#破解步骤" aria-hidden="true">#</a> 破解步骤</h3><p>拷贝Crack文件夹下文件替换安装目录下同名文件</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271011552.png" alt="1629958585548"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271011842.png" alt="1629958607468"></p><h2 id="envi多光谱大气校正" tabindex="-1"><a class="header-anchor" href="#envi多光谱大气校正" aria-hidden="true">#</a> Envi多光谱大气校正</h2><h3 id="_1-软件准备" tabindex="-1"><a class="header-anchor" href="#_1-软件准备" aria-hidden="true">#</a> 1.软件准备</h3><p>Envi 5.2</p><h3 id="_2-数据准备" tabindex="-1"><a class="header-anchor" href="#_2-数据准备" aria-hidden="true">#</a> 2.数据准备</h3><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271012901.png" alt="1629962112654"></p><h3 id="_3-信息备份" tabindex="-1"><a class="header-anchor" href="#_3-信息备份" aria-hidden="true">#</a> 3.信息备份</h3><p>备份一下处理过程中需要的信息，以免到时候计算麻烦</p><h4 id="_1-time" tabindex="-1"><a class="header-anchor" href="#_1-time" aria-hidden="true">#</a> （1）Time</h4><p>2020-10-17T03:02:14Z</p><p>右键-&gt;View Metadata-&gt;Time</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271012586.png" alt="1629962364676"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271012556.png" alt="1629962377909"></p><h4 id="_2-atmospheric-model-大气模式" tabindex="-1"><a class="header-anchor" href="#_2-atmospheric-model-大气模式" aria-hidden="true">#</a> （2）Atmospheric Model( 大气模式)</h4><p>Tropical</p><p>大气模式有以下几种</p><table><thead><tr><th style="text-align:center;">Model Atmosphere</th><th style="text-align:center;">Water Vapor (std atm-cm)</th><th style="text-align:center;">Water Vapor(g/cm2)</th><th style="text-align:center;">Surface Air Temperature</th></tr></thead><tbody><tr><td style="text-align:center;">Sub-Arctic Winter (SAW)</td><td style="text-align:center;">518</td><td style="text-align:center;">0.42</td><td style="text-align:center;">-16° C (3° F)</td></tr><tr><td style="text-align:center;">Mid-Latitude Winter (MLW)</td><td style="text-align:center;">1060</td><td style="text-align:center;">0.85</td><td style="text-align:center;">-1° C (30° F)</td></tr><tr><td style="text-align:center;">U.S. Standard (US)</td><td style="text-align:center;">1762</td><td style="text-align:center;">1.42</td><td style="text-align:center;">15° C (59° F)</td></tr><tr><td style="text-align:center;">Sub-Arctic Summer (SAS)</td><td style="text-align:center;">2589</td><td style="text-align:center;">2.08</td><td style="text-align:center;">14° C (57° F)</td></tr><tr><td style="text-align:center;">Mid-Latitude Summer (MLS)</td><td style="text-align:center;">3636</td><td style="text-align:center;">2.92</td><td style="text-align:center;">21° C (70° F)</td></tr><tr><td style="text-align:center;">Tropical (T)</td><td style="text-align:center;">5119</td><td style="text-align:center;">4.11</td><td style="text-align:center;">27° C (80° F)</td></tr></tbody></table><p>根据经纬度和时间可以选定研究区的大气模式，见下图。</p><table><thead><tr><th style="text-align:center;">Latitude (°N)</th><th style="text-align:center;">Jan</th><th style="text-align:center;">March</th><th style="text-align:center;">May</th><th style="text-align:center;">July</th><th style="text-align:center;">Sept</th><th style="text-align:center;">Nov</th></tr></thead><tbody><tr><td style="text-align:center;">80</td><td style="text-align:center;">SAW</td><td style="text-align:center;">SAW</td><td style="text-align:center;">SAW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">SAW</td></tr><tr><td style="text-align:center;">70</td><td style="text-align:center;">SAW</td><td style="text-align:center;">SAW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">SAW</td></tr><tr><td style="text-align:center;">60</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">SAS</td><td style="text-align:center;">SAS</td><td style="text-align:center;">MLW</td></tr><tr><td style="text-align:center;">50</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">SAS</td><td style="text-align:center;">SAS</td><td style="text-align:center;">SAS</td><td style="text-align:center;">SAS</td></tr><tr><td style="text-align:center;">40</td><td style="text-align:center;">SAS</td><td style="text-align:center;">SAS</td><td style="text-align:center;">SAS</td><td style="text-align:center;">MLS</td><td style="text-align:center;">MLS</td><td style="text-align:center;">SAS</td></tr><tr><td style="text-align:center;">30</td><td style="text-align:center;">MLS</td><td style="text-align:center;">MLS</td><td style="text-align:center;">MLS</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">MLS</td></tr><tr><td style="text-align:center;">20</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td></tr><tr><td style="text-align:center;">10</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td></tr><tr><td style="text-align:center;">0</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td></tr><tr><td style="text-align:center;">-10</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td></tr><tr><td style="text-align:center;">-20</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">T</td><td style="text-align:center;">MLS</td><td style="text-align:center;">MLS</td><td style="text-align:center;">T</td></tr><tr><td style="text-align:center;">-30</td><td style="text-align:center;">MLS</td><td style="text-align:center;">MLS</td><td style="text-align:center;">MLS</td><td style="text-align:center;">MLS</td><td style="text-align:center;">MLS</td><td style="text-align:center;">MLS</td></tr><tr><td style="text-align:center;">-40</td><td style="text-align:center;">SAS</td><td style="text-align:center;">SAS</td><td style="text-align:center;">SAS</td><td style="text-align:center;">SAS</td><td style="text-align:center;">SAS</td><td style="text-align:center;">SAS</td></tr><tr><td style="text-align:center;">-50</td><td style="text-align:center;">SAS</td><td style="text-align:center;">SAS</td><td style="text-align:center;">SAS</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">SAS</td></tr><tr><td style="text-align:center;">-60</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td></tr><tr><td style="text-align:center;">-70</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td></tr><tr><td style="text-align:center;">-80</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td><td style="text-align:center;">MLW</td></tr></tbody></table><h4 id="_3-aerosol-model-气溶胶模式" tabindex="-1"><a class="header-anchor" href="#_3-aerosol-model-气溶胶模式" aria-hidden="true">#</a> （3） Aerosol Model(气溶胶模式)</h4><p>Tropospheric</p><p>有以下几种</p><ul><li><strong>Rural:</strong> 表示不受城市或工业来源严重影响的区域中的气溶胶。颗粒大小是两种分布的混合，一种是大的，一种是小的。</li><li><strong>Urban:</strong> 80%的农村气溶胶与20%的煤烟状气溶胶的混合物，适用于高密度城市/工业区。</li><li><strong>Maritime:</strong> 表示在海洋盛行风作用下，海洋或大陆上的边界层。它由两种成分组成，一种来自海上喷雾，另一种来自农村大陆气溶胶（忽略了最大的颗粒）。</li><li><strong>Tropospheric:</strong> 适用于陆地上的平静、晴朗（能见度大于40公里）条件，由乡村模型的小颗粒组成。</li></ul><h5 id="_4-平均海拔" tabindex="-1"><a class="header-anchor" href="#_4-平均海拔" aria-hidden="true">#</a> (4)平均海拔</h5><p>127M</p><p>(1)、打开需要统计区域对应的图像。</p><p>(2)、选择File-&gt;Open World Data -&gt;Elevation(GMTED2010),打开ENVI自带全球900米分辨率的DEM数据。</p><p>注：如果其他版本，需要打开其他DEM数据，如90米的srtm或者30米的G-DEM数据。</p><p>(3)、在Toolbox中，选择/Statistics/Compute Statistics，打开Compute Statistics输入文件对话框，选择GMTED2010.jp2数据。单击Stats Subset按钮，打开Select Statistics Subset对话框。</p><p>(4)、在Select Statistics Subset对话框中，单击File按钮，选择统计区域对应的图像，单击Ok。</p><p>(5)、在统计面板中，默认选择Basic Stats基本统计即可，这样就可以得到平均海拔高程127米。</p><h3 id="数据处理" tabindex="-1"><a class="header-anchor" href="#数据处理" aria-hidden="true">#</a> 数据处理</h3><h4 id="_1-先完成辐射定标处理" tabindex="-1"><a class="header-anchor" href="#_1-先完成辐射定标处理" aria-hidden="true">#</a> （1）先完成辐射定标处理</h4><h4 id="_2-使用-flaash-atmospheric-correction-工具" tabindex="-1"><a class="header-anchor" href="#_2-使用-flaash-atmospheric-correction-工具" aria-hidden="true">#</a> （2）使用 FLAASH Atmospheric Correction 工具</h4><p>在Toolbox中，打开/Radiometric Correction/Atmospheric Correction Module/FLAASH Atmospheric Correction。</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111031055377.png" alt="1629963438262"></p><h4 id="_3-输入参数" tabindex="-1"><a class="header-anchor" href="#_3-输入参数" aria-hidden="true">#</a> （3）输入参数</h4><ol><li><p>点击Input Radiance Image，前面辐射定标好的数据 ，在Radiance Scale Factors面板中选择Use single scale factor for all bands，由于定标的辐射量数据与FLAASH的辐射亮度的单位一致，所以在此Single scale factor选择：1，单击OK；</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271012686.png" alt="1629963542983"></p></li></ol><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271012536.png" alt="1629963560452"></p><p>2.设置输出文件和文件夹</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271012176.png" alt="1629963685668"></p><ol start="3"><li><p>传感器基本信息设置：</p><p>成像中心点经纬度FLAASH自动从影像中获取。</p><p>传感器高度（Sensor Altitude）：645km</p><p>像元大小（pixel Size）：8m</p><p>成像区域平均高度可以通过统计DEM数据获取</p><p>成像时间：在图层管理中右键选View metadata，在Time选项中可以获取。</p></li></ol><p>4.设置大气模式与气溶胶模式</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271012187.png" alt="1629964134417"></p><h4 id="_4-处理前后结果对比" tabindex="-1"><a class="header-anchor" href="#_4-处理前后结果对比" aria-hidden="true">#</a> （4）处理前后结果对比</h4><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271012839.png" alt="1629964481414"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271012913.png" alt="1629964490115"></p><h2 id="envi辐射定标" tabindex="-1"><a class="header-anchor" href="#envi辐射定标" aria-hidden="true">#</a> Envi辐射定标</h2><h3 id="_1-加载数据" tabindex="-1"><a class="header-anchor" href="#_1-加载数据" aria-hidden="true">#</a> 1.加载数据</h3><p>选择Open As-&gt;CRESDA-&gt;GF-1。选择GF1_PMS2_E104.0_N36.0_20140724_L1A0000284766-PAN2.xml和GF1_PMS2_E104.0_N36.0_20140724_L1A0000284766-MSS2.xml文件打开。</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271012108.png" alt="1629962981939"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271012789.png" alt="1629963005406"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111031056177.png" alt="1629963028363"></p><h3 id="_2-打开-radiometric-calibration-工具" tabindex="-1"><a class="header-anchor" href="#_2-打开-radiometric-calibration-工具" aria-hidden="true">#</a> （2）打开 Radiometric Calibration 工具</h3><p>在Toolbox中，打开/Radiometric Correction/Radiometric Calibration，选择多光谱数据。</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111031056178.png" alt="1629963101777"></p><p>点击Apply FLAASH Settings</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271012738.png" alt="1629963120501"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271012786.png" alt="1629963141587"></p><p>选择输出文件</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271012123.png" alt="1629963170389"></p><p>点击OK后等待一段时间</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111031056182.png" alt="1629963217941"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111031056183.png" alt="1629963336229"></p>',89),l={},i=(0,n(63243).Z)(l,[["render",function(t,e){return a}]])},63243:(t,e)=>{e.Z=(t,e)=>{const n=t.__vccOpts||t;for(const[t,a]of e)n[t]=a;return n}}}]);